+/**
+ * Replaces recursive placeholders in a type.
+ */
+type ReplaceRecur<TValue, TRecur> = TValue extends RecurSchema
+  ? TRecur
+  : TValue extends Map<infer TKey, infer TItem>
+    ? Map<ReplaceRecur<TKey, TRecur>, ReplaceRecur<TItem, TRecur>>
+    : TValue extends Set<infer TItem>
+      ? Set<ReplaceRecur<TItem, TRecur>>
+      : TValue extends readonly (infer TItem)[]
+        ? ReplaceRecur<TItem, TRecur>[]
+        : TValue extends object
+          ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TRecur> }
+          : TValue;
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    ReplaceRecur<InferInput<TWrapped>, RecursiveSchema<TWrapped>>,
+    ReplaceRecur<InferOutput<TWrapped>, RecursiveSchema<TWrapped>>,
+    InferIssue<TWrapped>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recursive';
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Replaces recursive placeholders with a recursive schema.
+ *
+ * @param value The value to replace placeholders in.
+ * @param schema The recursive schema.
+ *
+ * @returns The value with placeholders replaced.
+ */
+function replaceRecur<TValue>(value: TValue, schema: RecurSchema): TValue {
+  if (value === Recur) {
+    return schema as TValue;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+
+  let copy: object | undefined;
+  for (const key of Reflect.ownKeys(value)) {
+    const descriptor = Object.getOwnPropertyDescriptor(value, key);
+    if (descriptor && 'value' in descriptor) {
+      const replacement = replaceRecur(descriptor.value, schema);
+      if (replacement !== descriptor.value) {
+        copy ??= Object.create(Object.getPrototypeOf(value));
+        if (copy !== value) {
+          Object.defineProperties(copy, Object.getOwnPropertyDescriptors(value));
+        }
+        Object.defineProperty(copy, key, { ...descriptor, value: replacement });
+      }
+    }
+  }
+  return (copy ?? value) as TValue;
+}
+
+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false as const,
+    wrapped: undefined as unknown as TWrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset: Parameters<TWrapped['~run']>[0], config: Parameters<TWrapped['~run']>[1]) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  };
+  schema.wrapped = replaceRecur(wrapped, schema as RecurSchema);
+  return schema as RecursiveSchema<TWrapped>;
+}
